import java.util.*;

public class Solution {
    private static final int MOD = (int)1e9 + 7;

    public static long solve(long[][] points) {
        Map<Long, List<Long>> yToXs = new HashMap<>();
        for (long[] point : points) {
            long x = point[0];
            long y = point[1];
            yToXs.computeIfAbsent(y, k -> new ArrayList<>()).add(x);
        }

        for (List<Long> xs : yToXs.values()) {
            Collections.sort(xs);
        }

        Map<String, Integer> yPairs = new HashMap<>();
        List<Long> ys = new ArrayList<>(yToXs.keySet());
        Collections.sort(ys);

        for (long y : ys) {
            List<Long> xs = yToXs.get(y);
            int m = xs.size();
            if (m >= 2) {
                for (int i = 0; i < m; i++) {
                    for (int j = i + 1; j < m; j++) {
                        long dx = xs.get(j) - xs.get(i);
                        String key = y + "," + dx;
                        yPairs.put(key, yPairs.getOrDefault(key, 0) + 1);
                    }
                }
            }
        }

        long total = 0;
        for (int cnt : yPairs.values()) {
            if (cnt >= 2) {
                total += (long) cnt * (cnt - 1) / 2;
            }
        }

        return total % MOD;
    }
}
